wp:postmeta.wp:meta_value:
/* Tighten spacing around the TOC and immediately following heading */
.toc_container { margin-bottom: 0.5rem !important; }          /* your TOC may use a different class */
.entry-content h2, .entry-content h3 { margin-top: 1.2rem; margin-bottom: 0.6rem; }

/* Remove extra space when a paragraph with only  precedes a list */
.entry-content p:has(> strong:only-child) { margin-bottom: 0.25rem; }  /* modern browsers support :has */
.entry-content p + ul { margin-top: 0.25rem; }

/* Lists inside this section a bit tighter overall */
#author-profiles-directory + * + h2 + p + h3 + p + ul,
.entry-content ul { margin-top: 0.25rem; margin-bottom: 0.75rem; }

/* Directory table already has margin-bottom: 1em inline; trim it globally if needed */
#author-profiles-directory table { margin-bottom: 0.5rem !important; }

/* Optional: small adjustment to the profile-links line under each faculty name */
.author-profiles { margin: 0.4rem 0 0.6rem; }
``
